import json
from typing import Any, Dict, Optional
from flask import Flask, request
from jwt import PyJWTError, decode
from jwt.algorithms import RSAAlgorithm, HMACAlgorithm

app = Flask(__name__)

# Define the allowed algorithms for JWT verification
ALLOWED_ALGORITHMS = {
    "HS256": HMACAlgorithm(HMACAlgorithm.SHA256),
    "RS256": RSAAlgorithm(RSAAlgorithm.SHA256)
}

# Define the required claims for JWT verification
REQUIRED_CLAIMS = ["exp"]

@app.route("/", methods=["POST"])
def verify_jwt():
    # Get the JWT token from the request body
    token = request.get_json()["token"]

    # Decode the JWT token and verify its signature using the allowed algorithms
    try:
        payload = decode(token, key=None, algorithms=ALLOWED_ALGORITHMS)
    except PyJWTError as e:
        return json.dumps({"error": str(e)}), 401

    # Verify the required claims are present in the payload
    for claim in REQUIRED_CLAIMS:
        if claim not in payload:
            return json.dumps({"error": f"Missing required claim '{claim}'"}), 401

    # Return the decoded payload as JSON
    return json.dumps(payload)